13.  * Manages type-safe bidirectional communication between webview and extension.
14.  */
15. class WebviewRpcClient {
16. 	constructor() {
17. 		// Acquire VS Code API
18. 		// @ts-ignore - acquireVsCodeApi is provided by VS Code webview
19. 		this.vscode = acquireVsCodeApi();
20. 		
21. 		// Handler registry
22. 		this.handlers = new Map();
23. 		
