104. 	 */
105. 	viewDiff(data) {
106. 		this._send({
107. 			type: 'viewDiff',
108. 			data
109. 		});
110. 	}
111. 	
112. 	/**
113. 	 * Toggle plan mode on/off
114. 	 * @param {boolean} enabled - Enable or disable plan mode
115. 	 */
116. 	togglePlanMode(enabled) {
117. 		this._send({
118. 			type: 'togglePlanMode',
119. 			enabled
120. 		});
121. 	}
122. 	
123. 	/**
124. 	 * User accepted plan
125. 	 */
126. 	acceptPlan() {
127. 		this._send({
128. 			type: 'acceptPlan'
129. 		});
130. 	}
131. 	
