136. 		this._send({
137. 			type: 'rejectPlan'
138. 		});
139. 	}
140. 	
141. 	/**
142. 	 * Open file picker for attachments
143. 	 */
144. 	pickFiles() {
145. 		this._send({
146. 			type: 'pickFiles'
147. 		});
148. 	}
149. 	
150. 	/**
151. 	 * Show plan content (/review command)
152. 	 */
153. 	showPlanContent() {
154. 		this._send({
155. 			type: 'showPlanContent'
156. 		});
157. 	}
