	rpc.showMcpConfig();
});

eventBus.on('showUsageMetrics', () => {
	console.log('[Slash Command] Show usage metrics (/usage)');
	rpc.showUsageMetrics();
});

eventBus.on('showHelp', (args) => {
	console.log('[Slash Command] Show help (/help)', args);
