1. /**
2.  * CommandParser Service
3.  * 
4.  * Parses, validates, and executes slash commands
5.  * 
6.  * Responsibilities:
7.  * - Parse text input for slash commands
8.  * - Validate commands against current context (plan mode state)
9.  * - Execute commands by emitting appropriate events
10.  * 
11.  * Usage:
12.  *   const parser = new CommandParser();
13.  *   const cmd = parser.parse('/plan');
14.  *   if (cmd && parser.isValid(cmd, context)) {
15.  *     parser.execute(cmd, eventBus);
16.  *   }
17.  */
18. export class CommandParser {
19. 	constructor() {
20. 		// Command registry: command name -> { type, event, instruction, requiredContext, category, description }
21. 		this.commands = new Map([
22. 			// Extension commands (10)
23. 			['plan', {
24. 				type: 'extension',
25. 				event: 'enterPlanMode',
26. 				requiredContext: { planMode: false },
27. 				category: 'plan',
28. 				description: 'Enter plan mode'
29. 			}],
30. 			['exit', {
31. 				type: 'extension',
32. 				event: 'exitPlanMode',
33. 				requiredContext: { planMode: true },
34. 				category: 'plan',
35. 				description: 'Exit plan mode'
36. 			}],
37. 			['accept', {
38. 				type: 'extension',
39. 				event: 'acceptPlan',
40. 				requiredContext: { planMode: true, planReady: true },
41. 				category: 'plan',
42. 				description: 'Accept the plan'
43. 			}],
44. 			['reject', {
45. 				type: 'extension',
46. 				event: 'rejectPlan',
47. 				requiredContext: { planMode: true, planReady: true },
48. 				category: 'plan',
49. 				description: 'Reject the plan'
50. 			}],
51. 			['review', {
52. 				type: 'extension',
53. 				event: 'showPlanContent',
54. 				category: 'code',
55. 				description: 'View plan content'
56. 			}],
57. 			['diff', {
58. 				type: 'extension',
59. 				event: 'openDiffView',
60. 				category: 'code',
61. 				description: 'Compare two files'
62. 			}],
63. 			['mcp', {
64. 				type: 'extension',
65. 				event: 'showMcpConfig',
66. 				category: 'config',
67. 				description: 'MCP server config'
68. 			}],
69. 			['usage', {
70. 				type: 'extension',
71. 				event: 'showUsageMetrics',
72. 				category: 'config',
73. 				description: 'Usage metrics'
74. 			}],
75. 			['help', {
76. 				type: 'extension',
77. 				event: 'showHelp',
78. 				category: 'config',
79. 				description: 'Command reference'
80. 			}],
81. 			['model', {
82. 				type: 'extension',
83. 				event: 'showModelSelector',
84. 				category: 'session',
85. 				description: 'Switch model'
86. 			}],
87. 			['rename', {
88. 				type: 'extension',
89. 				event: 'renameSession',
90. 				category: 'session',
91. 				description: 'Rename this session'
92. 			}],
93. 			['agent', {
94. 				type: 'extension',
95. 				event: 'selectAgent',
96. 				category: 'session',
97. 				description: 'Set active agent (or clear with no args)'
98. 			}],
99. 
100. 			// CLI Passthrough commands (6)
101. 			['delegate', {
102. 				type: 'passthrough',
103. 				instruction: 'The /delegate command opens GitHub Copilot coding agent in a new PR. Opening terminal...',
104. 				category: 'cli',
105. 				description: 'GitHub Copilot agent'
106. 			}],
107. 			['skills', {
108. 				type: 'passthrough',
109. 				instruction: 'The /skills command manages custom scripts and resources. Opening terminal...',
110. 				category: 'cli',
111. 				description: 'Custom scripts'
112. 			}],
113. 			['plugin', {
114. 				type: 'passthrough',
115. 				instruction: 'The /plugin command installs extensions from the marketplace. Opening terminal...',
116. 				category: 'cli',
117. 				description: 'Install plugins'
118. 			}],
119. 			['login', {
120. 				type: 'passthrough',
121. 				instruction: 'Opening terminal to authenticate with GitHub Copilot...',
122. 				category: 'cli',
123. 				description: 'Authenticate'
124. 			}],
125. 			['logout', {
126. 				type: 'passthrough',
127. 				instruction: 'Opening terminal to log out of GitHub Copilot...',
128. 				category: 'cli',
129. 				description: 'Log out'
130. 			}],
131. 			
132. 			// Not supported commands (23)
133. 			['clear', { type: 'not-supported' }],
134. 			['new', { type: 'not-supported' }],
135. 			['resume', { type: 'not-supported' }],
136. 			['session', { type: 'not-supported' }],
137. 			['add-dir', { type: 'not-supported' }],
138. 			['list-dirs', { type: 'not-supported' }],
139. 			['cwd', { type: 'not-supported' }],
140. 			['cd', { type: 'not-supported' }],
141. 			['context', { type: 'not-supported' }],
142. 			['compact', { type: 'extension', event: 'compact', category: 'session', description: 'Free context window space' }],
143. 			['lsp', { type: 'not-supported' }],
144. 			['theme', { type: 'not-supported' }],
145. 			['terminal-setup', { type: 'not-supported' }],
146. 			['init', { type: 'not-supported' }],
147. 			['allow-all', { type: 'not-supported' }],
148. 			['yolo', { type: 'not-supported' }],
149. 			['reset-allowed-tools', { type: 'not-supported' }],
150. 			['user', { type: 'not-supported' }],
151. 			['feedback', { type: 'not-supported' }],
152. 			['share', { type: 'not-supported' }],
153. 			['experimental', { type: 'not-supported' }],
154. 			['ide', { type: 'not-supported' }],
155. 			['quit', { type: 'not-supported' }]
156. 		]);
157. 	}
158. 
159. 	/**
160. 	 * Parse text for slash command
161. 	 * @param {string} text - User input text
162. 	 * @returns {Object|null} { command: string, args: string[] } or null
163. 	 */
164. 	parse(text) {
165. 		// Validate input
166. 		if (!text || typeof text !== 'string') {
167. 			return null;
168. 		}
169. 
170. 		// Must start with slash
171. 		if (!text.startsWith('/')) {
172. 			return null;
173. 		}
174. 
175. 		// Split into parts
176. 		const parts = text.trim().split(/\s+/);
177. 		const commandWithSlash = parts[0];
178. 
179. 		// Extract command name (remove /)
180. 		const command = commandWithSlash.substring(1).toLowerCase();
181. 		const args = parts.slice(1);
182. 
183. 		return { command, args };
184. 	}
185. 
186. 	/**
187. 	 * Check if command is registered
188. 	 * @param {string} commandName - Command name (without /)
189. 	 * @returns {boolean}
190. 	 */
191. 	isRegistered(commandName) {
192. 		return this.commands.has(commandName);
193. 	}
194. 
195. 	/**
196. 	 * Validate command against current context
197. 	 * @param {Object} cmd - Parsed command { command, args }
198. 	 * @param {Object} context - Current state { planMode, planReady, ... }
199. 	 * @returns {boolean}
200. 	 */
201. 	isValid(cmd, context = {}) {
202. 		if (!cmd || !cmd.command) {
203. 			return false;
204. 		}
205. 
206. 		const commandDef = this.commands.get(cmd.command);
207. 
208. 		// Unknown commands are not valid
209. 		if (!commandDef) {
210. 			return false;
211. 		}
212. 
213. 		// If no context requirements, command is valid
214. 		if (!commandDef.requiredContext) {
215. 			return true;
216. 		}
217. 
218. 		// Check all required context conditions
219. 		return Object.entries(commandDef.requiredContext).every(
220. 			([key, expectedValue]) => context[key] === expectedValue
221. 		);
222. 	}
223. 
224. 	/**
225. 	 * Execute command by emitting event
226. 	 * @param {Object} cmd - Parsed command { command, args }
227. 	 * @param {EventBus} eventBus - Event bus to emit to
228. 	 */
229. 	execute(cmd, eventBus) {
230. 		if (!cmd || !cmd.command) {
231. 			return;
232. 		}
233. 
234. 		const commandDef = this.commands.get(cmd.command);
235. 
236. 		if (!commandDef) {
237. 			console.warn(`[CommandParser] Unknown command: ${cmd.command}`);
238. 			return;
239. 		}
240. 
241. 		// Route by command type
242. 		switch (commandDef.type) {
243. 			case 'extension':
244. 				eventBus.emit(commandDef.event, cmd.args);
245. 				break;
246. 			case 'passthrough':
247. 				eventBus.emit('openInCLI', [cmd.command, ...cmd.args]);
248. 				break;
249. 			case 'not-supported':
250. 				eventBus.emit('showNotSupported', [cmd.command]);
251. 				break;
252. 			default:
253. 				console.warn(`[CommandParser] Unknown command type: ${commandDef.type}`);
254. 				break;
255. 		}
256. 	}
257. 
258. 	/**
259. 	 * Get event name for a command
260. 	 * @param {string} commandName - Command name (without /)
261. 	 * @returns {string|null}
262. 	 */
263. 	getEvent(commandName) {
264. 		const commandDef = this.commands.get(commandName);
265. 		return commandDef ? commandDef.event : null;
266. 	}
267. 
268. 	/**
269. 	 * Register a new command (for future extensibility)
270. 	 * @param {string} commandName - Command name (without /)
271. 	 * @param {string} eventName - Event to emit
272. 	 * @param {Object} requiredContext - Context requirements
273. 	 */
274. 	register(commandName, eventName, requiredContext = null) {
275. 		this.commands.set(commandName, {
276. 			event: eventName,
277. 			requiredContext
278. 		});
279. 	}
280. 
281. 	/**
282. 	 * Get all registered command names
283. 	 * @returns {string[]}
284. 	 */
285. 	getCommandNames() {
286. 		return Array.from(this.commands.keys());
287. 	}
288. 
289. 	/**
290. 	 * Get command type
291. 	 * @param {string} commandName - Command name (without /)
292. 	 * @returns {'extension'|'passthrough'|'not-supported'|null}
293. 	 */
294. 	getCommandType(commandName) {
295. 		if (!commandName) {
296. 			return null;
297. 		}
298. 		
299. 		const commandDef = this.commands.get(commandName);
300. 		return commandDef ? commandDef.type : null;
301. 	}
302. 
303. 	/**
304. 	 * Check if command is an extension command
305. 	 * @param {string} commandName - Command name (without /)
306. 	 * @returns {boolean}
307. 	 */
308. 	isExtensionCommand(commandName) {
309. 		return this.getCommandType(commandName) === 'extension';
310. 	}
311. 
312. 	/**
313. 	 * Check if command is a passthrough command
314. 	 * @param {string} commandName - Command name (without /)
315. 	 * @returns {boolean}
316. 	 */
317. 	isPassthroughCommand(commandName) {
318. 		return this.getCommandType(commandName) === 'passthrough';
319. 	}
320. 
321. 	/**
322. 	 * Check if command is not supported
323. 	 * @param {string} commandName - Command name (without /)
324. 	 * @returns {boolean}
325. 	 */
326. 	isNotSupportedCommand(commandName) {
327. 		return this.getCommandType(commandName) === 'not-supported';
328. 	}
329. 
330. 	/**
331. 	 * Get instruction text for passthrough commands
332. 	 * @param {string} commandName - Command name (without /)
333. 	 * @returns {string|null}
334. 	 */
335. 	getInstruction(commandName) {
336. 		const commandDef = this.commands.get(commandName);
337. 		return (commandDef && commandDef.instruction) ? commandDef.instruction : null;
338. 	}
339. 
340. 	/**
341. 	 * Get visible commands for the slash command panel
342. 	 * Returns extension and passthrough commands (excludes not-supported)
343. 	 * @returns {Array<{name: string, description: string, category: string}>}
344. 	 */
345. 	getVisibleCommands() {
346. 		const result = [];
347. 		for (const [name, def] of this.commands) {
348. 			if (def.type === 'extension' || def.type === 'passthrough') {
349. 				result.push({
350. 					name,
351. 					description: def.description,
352. 					category: def.category
353. 				});
354. 			}
355. 		}
356. 		return result;
357. 	}
358. }
359.

